local ADDON_NAME, ns = ...
if GetLocale() ~= "deDE" then return end
local L = ns.L

L["%s only"] = "Nur %s"
L["0 (professions only)"] = "0 (nur Berufe)"
L["About"] = "Über"
L["Adds this profession's recipes an item is used in to its tooltip, with the skill range that still gives points and whether you know the recipe."] = "Ergänzt den Tooltip eines Gegenstands um die Rezepte dieses Berufs, in denen er verwendet wird - mit dem Fertigkeitsbereich, der noch Punkte bringt, und ob Ihr das Rezept kennt."
L["Also annotates reagents of professions this character does not have (as if at skill 0) - useful to decide what to keep or send to alts."] = "Beschriftet auch Materialien von Berufen, die dieser Charakter nicht hat (wie bei Fertigkeit 0) - hilfreich bei der Entscheidung, was behalten oder an Twinks geschickt wird."
L["Always show"] = "Immer anzeigen"
L["Author: %s"] = "Autor: %s"
L["Could not open the settings window on this client. Find the options under Game Menu -> Options -> AddOns -> ProfessionTips."] = "Das Einstellungsfenster konnte auf diesem Client nicht geöffnet werden. Die Optionen finden sich unter Spielmenü -> Optionen -> AddOns -> ProfessionTips."
L["Display"] = "Anzeige"
L["Include processed materials"] = "Weiterverarbeitete Materialien einbeziehen"
L["List only recipes this character has already learned. Unlearned recipes still count for the header's accumulated skill range and the '+N more' summary."] = "Nur Rezepte auflisten, die dieser Charakter bereits gelernt hat. Ungelernte Rezepte zählen weiterhin für den Fertigkeitsbereich in der Kopfzeile und die '+N weitere'-Zusammenfassung."
L["more recipes give points"] = "weitere Rezepte geben Punkte"
L["no skillups"] = "keine Punkte mehr"
L["not learned"] = "nicht gelernt"
L["Only add the tooltip information while this modifier key is held down."] = "Die Tooltip-Informationen nur anzeigen, während diese Zusatztaste gedrückt ist."
L["Only learned recipes"] = "Nur gelernte Rezepte"
L["processed material"] = "verarbeitetes Material"
L["Professions"] = "Berufe"
L["Raw materials also show the recipes of what they are processed into (cloth into bolts, ore into bars, hides into cured hides, ...), marked with 'via'."] = "Rohmaterialien zeigen auch die Rezepte ihrer Weiterverarbeitung (Stoff zu Ballen, Erz zu Barren, Häute zu gegerbten Häuten, ...), markiert mit 'via'."
L["Recipe lines per profession section. 0 shows only the profession headers with their accumulated skill range; otherwise at least 2 (the lowest- and highest-requirement recipes always appear together). More recipes are summarized as '+N more'."] = "Rezeptzeilen pro Berufsabschnitt. 0 zeigt nur die Berufs-Kopfzeilen mit ihrem gesammelten Fertigkeitsbereich; ansonsten mindestens 2 (das Rezept mit der niedrigsten und das mit der höchsten Anforderung erscheinen immer zusammen). Weitere Rezepte werden als '+N weitere' zusammengefasst."
L["Recipes listed per profession"] = "Angezeigte Rezepte pro Beruf"
L["Show for missing professions"] = "Für fehlende Berufe anzeigen"
L["Show only while holding"] = "Nur anzeigen bei gedrückter Taste"
L["Version: %s"] = "Version: %s"
L["via %s"] = "via %s"
